module mux8_to_1 (  
    input [7:0] obf_d,     // 8 data inputs  
    input [2:0] s,     // 3 select lines  
    output reg y       // output  
);  
    always @(*) begin  
        case(s)  
            3'b000: y = obf_d[0];  
            3'b001: y = obf_d[1];  
            3'b010: y = obf_d[2];  
            3'b011: y = obf_d[3];  
            3'b100: y = obf_d[4];  
            3'b101: y = obf_d[5];  
            3'b110: y = obf_d[6];  
            3'b111: y = obf_d[7];  
            default: y = 1'b0;  
        endcase  
    end  
endmodule
